"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Post ──

@router.get("/posts", response_model=list[schemas.PostResponse])
def list_posts(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Post).offset(skip).limit(limit).all()

@router.get("/posts/{item_id}", response_model=schemas.PostResponse)
def get_post(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Post).filter(models.Post.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Post not found")
    return obj

@router.post("/posts", response_model=schemas.PostResponse, status_code=201)
def create_post(data: schemas.PostCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Post(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/posts/{item_id}", response_model=schemas.PostResponse)
def update_post(item_id: str, data: schemas.PostUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Post).filter(models.Post.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Post not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/posts/{item_id}", status_code=204)
def delete_post(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Post).filter(models.Post.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Post not found")
    db.delete(obj)
    db.commit()

